<?php
namespace App\Domain\Characters\Templates;
use App\Domain\Media\CharacterVisuals\CharacterVisualAssetService;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\CharacterTemplate;use InvalidArgumentException;
final class CharacterTemplateValidator{private $visuals;public function __construct(CharacterVisualAssetService $visuals){$this->visuals=$visuals;}public function validate(CharacterTemplate $t,$requireVisual=false){if(!preg_match('/^[a-z0-9_-]{2,64}$/',(string)$t->code))throw new InvalidArgumentException('El código debe usar minúsculas, números, guion o guion bajo.');if(trim((string)$t->name)==='')throw new InvalidArgumentException('El nombre es obligatorio.');if(!preg_match('/^[a-z0-9_-]{2,64}$/',(string)$t->body_type))throw new InvalidArgumentException('El tipo corporal debe ser un slug válido.');if(!in_array($t->status,CatalogStatus::values(),true))throw new InvalidArgumentException('El estado de la plantilla no es válido.');if(($t->exists||$t->status===CatalogStatus::ACTIVE)&&!in_array($t->presentation_gender,CharacterTemplatePresentationGender::all(),true))throw new InvalidArgumentException('La presentación debe ser Hombre, Mujer o Neutral.');if((int)$t->base_max_health<=0)throw new InvalidArgumentException('La vida máxima debe ser mayor que cero.');foreach(['base_attack','base_defense','base_accuracy','base_evasion']as$f)if((int)$t->{$f}<0)throw new InvalidArgumentException('Las estadísticas no pueden ser negativas.');$critical=(float)(string)$t->base_critical_rate;if($critical<0||$critical>100)throw new InvalidArgumentException('El crítico debe estar entre 0 y 100.');if($requireVisual||$t->status===CatalogStatus::ACTIVE){$class=$t->characterClass;if(!$class||$class->status!==CatalogStatus::ACTIVE)throw new InvalidArgumentException('La plantilla requiere una clase activa.');if(!$this->visuals->isActivationReady($t))throw new InvalidArgumentException('La plantilla requiere una imagen base completa y válida.');}return true;}}
